import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const TimbangMuat = () => {
  const navigate = useNavigate();

  const [rfid, setRfid] = useState(null);
  const [truck, setTruck] = useState(null);
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({
    itemType: '',
    quantity: '',
    bruto: '',
    tara: '',
    netto: 0
  });

  // Ambil RFID
  const fetchRFID = async () => {
    try {
      setLoading(true);
      const res = await axios.get('http://localhost:5000/api/rfid/latest');
      if (res.data.truck) {
        setRfid(res.data.truck.truckId);
        setTruck(res.data.truck);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  // Polling RFID
  useEffect(() => {
    const interval = setInterval(() => {
      if (!rfid) {
        fetchRFID();
      }
    }, 2000);
    return () => clearInterval(interval);
  }, [rfid]);

  // Kalkulasi Netto
  useEffect(() => {
    const bruto = parseFloat(form.bruto) || 0;
    const tara = parseFloat(form.tara) || 0;
    setForm(prev => ({ ...prev, netto: bruto - tara }));
  }, [form.bruto, form.tara]);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const payload = {
      truckId: rfid,
      ...form
    };

    try {
      await axios.post('http://localhost:5000/api/loadings', payload);
      alert("✅ Data timbang muat berhasil disimpan!");
      setForm({ itemType: '', quantity: '', bruto: '', tara: '', netto: 0 });
      setTruck(null);
      setRfid(null);
    } catch (err) {
      console.error(err);
      alert("❌ Gagal menyimpan data timbang muat");
    }
  };

  return (
    <div className="p-8 min-h-screen bg-gradient-to-br from-blue-100 to-white">
      <h1 className="text-3xl font-bold text-center mb-8">📦 Timbang Muat</h1>

      {loading && (
        <div className="flex justify-center items-center my-10">
          <div className="animate-spin rounded-full h-16 w-16 border-t-4 border-blue-500"></div>
        </div>
      )}

      {!truck && !loading && (
        <div className="text-center text-lg text-gray-600 mb-8">
          🔄 Menunggu scan RFID...
        </div>
      )}

      {truck && (
        <div className="max-w-2xl mx-auto bg-white rounded-lg shadow-lg p-6">
          <h2 className="text-xl font-semibold mb-4 text-center text-blue-600">Data Truk</h2>
          <div className="grid grid-cols-2 gap-4 mb-6">
            <div><strong>Truck ID:</strong> {truck.truckId}</div>
            <div><strong>Driver:</strong> {truck.driver}</div>
            <div><strong>Tipe Truck:</strong> {truck.truckType}</div>
            <div><strong>Tanggal:</strong> {truck.date?.split('T')[0]}</div>
          </div>

          <form onSubmit={handleSubmit} className="grid grid-cols-2 gap-4">
            <div>
              <label>Jenis Barang:</label>
              <input type="text" name="itemType" value={form.itemType} onChange={handleChange} className="border p-2 w-full rounded" required />
            </div>

            <div>
              <label>Jumlah Barang:</label>
              <input type="number" name="quantity" value={form.quantity} onChange={handleChange} className="border p-2 w-full rounded" required />
            </div>

            <div>
              <label>Bruto (kg):</label>
              <input type="number" name="bruto" value={form.bruto} onChange={handleChange} className="border p-2 w-full rounded" required />
            </div>

            <div>
              <label>Tara (kg):</label>
              <input type="number" name="tara" value={form.tara} onChange={handleChange} className="border p-2 w-full rounded" required />
            </div>

            <div>
              <label>Netto (kg):</label>
              <input type="number" name="netto" value={form.netto} readOnly className="border p-2 w-full bg-gray-100 rounded" />
            </div>

            <div className="col-span-2 flex justify-end space-x-4 mt-4">
              <button type="button" onClick={() => navigate(-1)} className="bg-gray-400 hover:bg-gray-500 text-white px-4 py-2 rounded">
                Kembali
              </button>
              <button type="submit" className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded">
                Simpan
              </button>
            </div>
          </form>
        </div>
      )}
    </div>
  );
};

export default TimbangMuat;
